const weather = $('Fetch Weather').first().json;
const items = $('Fetch Surfaced Items').all().map((item, i) => ({
  digest_position: i + 1,
  title: item.json.title,
  ask: item.json.ask,
  detail: item.json.detail,
  consequence: item.json.consequence,
  deadline: item.json.deadline,
  urgency: item.json.urgency,
  source: item.json.source,
  id: item.json.id,
}));
const nags = $('Fetch Nag Items').all().map((item) => ({
  id: item.json.id,
  title: item.json.title,
}));
const date = new Date().toLocaleDateString('en-US', { timeZone: 'America/Chicago' });

return [{ json: { date, weather, items, nags } }];

const resp = $('Digest Synthesis (Claude Fable 5)').first().json;
const rendered_text = (resp.content && resp.content[0] && resp.content[0].text) || '';
const escape = (s) => (s ?? '').replace(/'/g, "''");
const items = $('Build Digest Payload').first().json.items || [];
const ids = items.map((it) => it.id);
const item_ids_sql = ids.length
  ? `ARRAY[${ids.map((id) => `'${id}'`).join(',')}]::uuid[]`
  : 'ARRAY[]::uuid[]';

return [{ json: {
  rendered_text_escaped: escape(rendered_text),
  item_ids_sql,
} }];
